class Solution:
    def countGoodIntegers(self, n: int, k: int) -> int:
        def count(d, odd, even):
            if d == 0:
                return 1
            res = 0
            for i in range(10):
                if i % k == 0:
                    if i == 0 and n > 1:
                        continue
                    if i % 2 == 0:
                        res += count(d - 1, odd, even + 1)
                    else:
                        res += count(d - 1, odd + 1, even)
            return res
        return count(n, 0, 0)
